  revalidateNotePaths(note);
  redirect(`/app/notes/${noteId}/edit?published=1`);
}

export async function unpublishNoteAction(noteId: string) {
  const owner = await requireOwnerSession();
  const note = await unpublishNote(owner.id, noteId);

  if (!note) {
    notFound();
  }

  revalidateNotePaths(note);
  redirect(`/app/notes/${noteId}/edit?unpublished=1`);
}

export async function retryNoteEnrichmentAction(noteId: string) {
  const owner = await requireOwnerSession();
  const note = await retryNoteEnrichment(owner.id, noteId);

  if (!note) {
    notFound();
  }

  if (note.enrichment.status === "pending") {
    scheduleNoteEnrichment(note, note.enrichment.attempts);
  }

  revalidateNotePaths(note);
  redirect(`/app/notes/${noteId}/edit?retried=1`);
}

import { NextResponse } from "next/server";

import { uploadNoteImage } from "@/features/media/service";
import { getOwnerSession } from "@/lib/auth/owner-session";

export async function POST(request: Request) {
  const session = await getOwnerSession();

  if (!session?.id) {
    return NextResponse.json(
      {
        error: "Sign in to upload note images."
      },
      {
        status: 401
      }
    );
  }

  try {
    const formData = await request.formData();
    const file = formData.get("file");

    if (!(file instanceof File)) {
      return NextResponse.json(
        {
          error: "Choose an image to upload."
        },
        {
          status: 400
        }
      );
    }

    const noteIdValue = formData.get("noteId");
    const noteId = typeof noteIdValue === "string" && noteIdValue.trim() ? noteIdValue.trim() : null;
    const uploadedImage = await uploadNoteImage({
      file,
      noteId,
      ownerId: session.id
    });

    return NextResponse.json(uploadedImage, {
      status: 201
    });
  } catch (error) {
    return NextResponse.json(
      {
        error: error instanceof Error ? error.message : "Image upload failed."
      },
      {
        status: 400
      }
    );
  }
}

import "server-only";

import NextAuth from "next-auth";
import Credentials from "next-auth/providers/credentials";

import { authConfig } from "@/auth.config";
import { env } from "@/lib/config/env";
import { DEMO_USER_ID } from "@/lib/auth/roles";
import { verifyPassword } from "@/lib/auth/password";
import { prisma } from "@/lib/prisma";

export const { handlers, signIn, signOut, auth } = NextAuth({
  ...authConfig,
  secret: env.authSecret,
  providers: [
    Credentials({
      credentials: {
        username: {
          label: "Username",
          type: "text"
        },
        password: {
          label: "Password",
          type: "password"
        }
      },
      async authorize(credentials) {
        const username = String(credentials?.username ?? "");
        const password = String(credentials?.password ?? "");

        if (!username || !password) {
          return null;
        }

        if (env.demoCredentials && username === env.demoCredentials.username && password === env.demoCredentials.password) {
          return {
            id: DEMO_USER_ID,
            name: username,
            role: "demo"
          };
        }

        const owner = await prisma.user.findUnique({ where: { username } });

        if (!owner || !verifyPassword(password, owner.passwordHash)) {
          return null;
        }

        return {
          id: owner.id,
          name: owner.username,
          role: "owner"
        };
      }
    })
  ],
  callbacks: {
    ...authConfig.callbacks,
    jwt({ token, user }) {
      if (user) {
        token.sub = user.id;
        token.name = user.name;
        token.role = user.role;
      }

      return token;
    },
    session({ session, token }) {
      if (session.user && token.sub) {
        session.user.id = token.sub;
        session.user.name = token.name ?? session.user.name;
        session.user.role = token.role === "demo" ? "demo" : "owner";
      }

      return session;
    }
  }
});

