"use server";

import { notFound, redirect } from "next/navigation";
import { revalidatePath } from "next/cache";
import { after } from "next/server";

import { runNoteEnrichment } from "@/features/notes/enrichment";
import {
  createDraftNote,
  publishNote,
  retryNoteEnrichment,
  startNoteEnrichment,
  unpublishNote,
  updateDraftNote
} from "@/features/notes/service";
import { requireWritableOwnerSession } from "@/lib/auth/owner-session";

function getNoteInput(formData: FormData) {
  return {
    title: String(formData.get("title") ?? ""),
    markdown: String(formData.get("markdown") ?? "")
  };
}

function revalidateNotePaths(note: { id: string; slug: string }) {
  revalidatePath("/");
  revalidatePath("/app");
  revalidatePath("/app/search");
  revalidatePath("/app/tags");
  revalidatePath(`/app/notes/${note.id}/edit`);
  revalidatePath(`/notes/${note.slug}`);
}

function scheduleNoteEnrichment(note: { id: string; slug: string }, attempt: number) {
  after(async () => {
    await runNoteEnrichment(note.id, attempt);
    revalidateNotePaths(note);
  });
}

async function queueNoteEnrichment(note: { id: string; slug: string }) {
  const enrichedNote = await startNoteEnrichment(note.id);

  if (enrichedNote.enrichment.status === "pending") {
    scheduleNoteEnrichment(note, enrichedNote.enrichment.attempts);
  }

  return enrichedNote;
}

export async function createNoteAction(formData: FormData) {
  const owner = await requireWritableOwnerSession();
  const note = await createDraftNote(owner.id, getNoteInput(formData));
  await queueNoteEnrichment(note);

  revalidateNotePaths(note);
  redirect(`/app/notes/${note.id}/edit?saved=1`);
}

export async function updateNoteAction(noteId: string, formData: FormData) {
  const owner = await requireWritableOwnerSession();
  const note = await updateDraftNote(owner.id, noteId, getNoteInput(formData));

  if (!note) {
    notFound();
  }

  await queueNoteEnrichment(note);
  revalidateNotePaths(note);
  redirect(`/app/notes/${noteId}/edit?saved=1`);
}

export async function publishNoteAction(noteId: string) {
  const owner = await requireWritableOwnerSession();
  const note = await publishNote(owner.id, noteId);

  if (!note) {
    notFound();
  }

  revalidateNotePaths(note);
  redirect(`/app/notes/${noteId}/edit?published=1`);
}

export async function unpublishNoteAction(noteId: string) {
  const owner = await requireWritableOwnerSession();
  const note = await unpublishNote(owner.id, noteId);

  if (!note) {
    notFound();
  }

  revalidateNotePaths(note);
  redirect(`/app/notes/${noteId}/edit?unpublished=1`);
}

export async function retryNoteEnrichmentAction(noteId: string) {
  const owner = await requireWritableOwnerSession();
  const note = await retryNoteEnrichment(owner.id, noteId);

  if (!note) {
    notFound();
  }

  if (note.enrichment.status === "pending") {
    scheduleNoteEnrichment(note, note.enrichment.attempts);
  }

  revalidateNotePaths(note);
  redirect(`/app/notes/${noteId}/edit?retried=1`);
}

"use server";

import { notFound, redirect } from "next/navigation";
import { revalidatePath } from "next/cache";
import { after } from "next/server";

import { runLinkEnrichment } from "@/features/links/enrichment";
import { LinkValidationError } from "@/features/links/normalize";
import {
  DuplicateLinkUrlError,
  createSavedLink,
  publishLink,
  refreshLinkFavicon,
  retryLinkEnrichment,
  startLinkFaviconRefresh,
  startLinkEnrichment,
  unpublishLink
} from "@/features/links/service";
import { requireWritableOwnerSession } from "@/lib/auth/owner-session";

function getLinkInput(formData: FormData) {
  return {
    url: String(formData.get("url") ?? ""),
    title: String(formData.get("title") ?? "")
  };
}

function revalidateLinkPaths() {
  revalidatePath("/");
  revalidatePath("/app/links");
  revalidatePath("/app/search");
  revalidatePath("/app/tags");
}

function scheduleLinkEnrichment(linkId: string, attempt: number) {
  after(async () => {
    await runLinkEnrichment(linkId, attempt);
    revalidateLinkPaths();
  });
}

function scheduleLinkFaviconRefresh(linkId: string) {
  after(async () => {
    await startLinkFaviconRefresh(linkId);
    revalidateLinkPaths();
  });
}

async function queueLinkEnrichment(linkId: string) {
  const link = await startLinkEnrichment(linkId);

  if (link.enrichment.status === "pending") {
    scheduleLinkEnrichment(link.id, link.enrichment.attempts);
  }

  return link;
}

export async function createLinkAction(formData: FormData) {
  const owner = await requireWritableOwnerSession();

  try {
    const link = await createSavedLink(owner.id, getLinkInput(formData));
    await queueLinkEnrichment(link.id);
    scheduleLinkFaviconRefresh(link.id);
  } catch (error) {
    if (error instanceof LinkValidationError) {
      redirect(`/app/links?error=${error.code}`);
    }

    if (error instanceof DuplicateLinkUrlError) {
      redirect("/app/links?error=duplicate-url");
    }

    throw error;
  }

  revalidateLinkPaths();
  redirect("/app/links?saved=1");
}

export async function refreshLinkFaviconAction(linkId: string) {
  const owner = await requireWritableOwnerSession();
  const link = await refreshLinkFavicon(owner.id, linkId);

  if (!link) {
    notFound();
  }

  await startLinkFaviconRefresh(link.id);
  revalidateLinkPaths();
  redirect("/app/links?favicon=1");
}

export async function retryLinkEnrichmentAction(linkId: string) {
  const owner = await requireWritableOwnerSession();
  const link = await retryLinkEnrichment(owner.id, linkId);

  if (!link) {
    notFound();
  }

  if (link.enrichment.status === "pending") {
    scheduleLinkEnrichment(link.id, link.enrichment.attempts);
  }

  revalidateLinkPaths();
  redirect("/app/links?retried=1");
}

export async function publishLinkAction(linkId: string) {
  const owner = await requireWritableOwnerSession();
  const link = await publishLink(owner.id, linkId);

  if (!link) {
    notFound();
  }

  revalidateLinkPaths();
  redirect("/app/links?published=1");
}

export async function unpublishLinkAction(linkId: string) {
  const owner = await requireWritableOwnerSession();
  const link = await unpublishLink(owner.id, linkId);

  if (!link) {
    notFound();
  }

  revalidateLinkPaths();
  redirect("/app/links?unpublished=1");
}
